import React, { useState, useEffect, useCallback } from 'react';
import Sidebar from '../components/shared/Sidebar';
import DataTable from '../components/shared/DataTable';
import api, { fmtCurrency, fmtDate, fmtDateTime } from '../utils/api';
import { useAuth } from '../context/AuthContext';
import { LineChart, Line, XAxis, YAxis, Tooltip, ResponsiveContainer } from 'recharts';
import {
  CalendarCheck, TrendingUp, DollarSign, Target,
  CheckCircle, XCircle, AlertCircle, Home, MapPin, Bed, Bath, Layers
} from 'lucide-react';

function StatCard({ icon: Icon, label, value, color = 'var(--accent)' }) {
  return (
    <div className="stat-card">
      <div className="stat-icon" style={{ background: `${color}22`, color }}><Icon size={18} /></div>
      <div className="stat-value">{value}</div>
      <div className="stat-label">{label}</div>
    </div>
  );
}

// ── Dashboard ─────────────────────────────────────────────────────────────────
function DashboardView({ agentId }) {
  const [perf, setPerf] = useState(null);
  const [profile, setProfile] = useState(null);
  const [error, setError] = useState('');

  useEffect(() => {
    if (!agentId) return;
    setError('');
    Promise.all([
      api.get(`/agent/profile/${agentId}`),
      api.get(`/agent/performance/${agentId}`)
    ])
      .then(([profileRes, perfRes]) => {
        setProfile(profileRes.data);
        setPerf(perfRes.data);
      })
      .catch(ex => setError(ex.response?.data?.detail || 'Failed to load dashboard. Is the backend running?'));
  }, [agentId]);

  if (error) return <div className="alert alert-error"><AlertCircle size={14} /> {error}</div>;
  if (!perf || !profile) return <div className="loading"><div className="spinner" />Loading…</div>;
  const s = perf.summary;

  return (
    <div>
      <div className="stats-grid">
        <StatCard icon={CalendarCheck} label="Total Appointments" value={s.total_appointments || 0} />
        <StatCard icon={CheckCircle} label="Successful Deals" value={s.successful_deals || 0} color="#4ade80" />
        <StatCard icon={Target} label="Conversion Rate" value={`${s.conversion_rate || 0}%`} color="#60a5fa" />
        <StatCard icon={DollarSign} label="Total Revenue" value={fmtCurrency(s.total_revenue)} color="#fbbf24" />
      </div>

      <div className="card" style={{ marginBottom: 20 }}>
        <div className="card-title"><TrendingUp size={16} /> Monthly Revenue</div>
        <div style={{ height: 240 }}>
          <ResponsiveContainer>
            <LineChart data={perf.monthly}>
              <XAxis dataKey="month" tick={{ fill: 'var(--text-muted)', fontSize: 11 }} tickLine={false} />
              <YAxis tick={{ fill: 'var(--text-muted)', fontSize: 10 }} tickFormatter={v => fmtCurrency(v)} tickLine={false} axisLine={false} />
              <Tooltip formatter={v => [fmtCurrency(v), 'Revenue']} contentStyle={{ background: 'var(--bg-card)', border: '1px solid var(--border)', borderRadius: 8 }} />
              <Line type="monotone" dataKey="revenue" stroke="var(--accent)" strokeWidth={2} dot={{ fill: 'var(--accent)' }} />
            </LineChart>
          </ResponsiveContainer>
        </div>
      </div>

      <div className="card">
        <div className="card-title">Agent Profile</div>
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12, fontSize: '0.88rem' }}>
          {[
            ['Name', profile.name], ['Email', profile.email], ['Phone', profile.phone],
            ['Manager', profile.manager_name], ['Hire Date', fmtDate(profile.hire_date)],
            ['Base Salary', fmtCurrency(profile.base_salary)],
          ].map(([k, v]) => (
            <div key={k} style={{ padding: '10px 14px', background: 'var(--bg-secondary)', borderRadius: 8 }}>
              <div style={{ fontSize: '0.72rem', color: 'var(--text-muted)', marginBottom: 2 }}>{k}</div>
              <div style={{ color: 'var(--text-primary)', fontWeight: 500 }}>{v}</div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

// ── Appointments ──────────────────────────────────────────────────────────────
function AppointmentsView({ agentId }) {
  const [apts, setApts] = useState([]);
  const [filter, setFilter] = useState('upcoming');
  const [actionModal, setActionModal] = useState(null);  // { apt, mode: 'success'|'fail' }
  const [rentForm, setRentForm] = useState({ rent_period_months: 12, security_deposit: '', rent_end_date: '' });
  const [msg, setMsg] = useState('');
  const [err, setErr] = useState('');
  const [loading, setLoading] = useState(false);

  const load = useCallback(() => {
    if (agentId) {
      api.get(`/agent/appointments/${agentId}?status=${filter}`)
        .then(r => setApts(r.data))
        .catch(ex => console.error('Appointments load error:', ex));
    }
  }, [agentId, filter]);

  useEffect(() => { load(); }, [load]);

  // Auto-calculate rent end date from months
  const handleRentMonthsChange = (months) => {
    const endDate = new Date();
    endDate.setMonth(endDate.getMonth() + Number(months));
    setRentForm(f => ({
      ...f,
      rent_period_months: months,
      rent_end_date: endDate.toISOString().split('T')[0]
    }));
  };

  const openSuccessModal = (apt) => {
    const defaultMonths = 12;
    const endDate = new Date();
    endDate.setMonth(endDate.getMonth() + defaultMonths);
    setRentForm({
      rent_period_months: defaultMonths,
      security_deposit: '',
      rent_end_date: endDate.toISOString().split('T')[0]
    });
    setErr('');
    setActionModal({ apt, mode: 'success' });
  };

  const handleCloseDeal = async (e) => {
    e.preventDefault();
    setErr('');
    setLoading(true);
    const apt = actionModal.apt;
    const dealType = apt.listing_type === 'RENT' ? 'RENT' : 'SALE';

    // For RENT validate security deposit
    if (dealType === 'RENT') {
      if (!rentForm.rent_end_date) { setErr('Rent end date is required.'); setLoading(false); return; }
      const today = new Date().toISOString().split('T')[0];
      if (rentForm.rent_end_date <= today) { setErr('Rent end date must be in the future.'); setLoading(false); return; }
    }

    try {
      await api.post('/agent/close-deal', {
        appointment_id: apt.appointment_id,
        deal_type: dealType,
        // Price is fixed — use listing price, not custom input
        sold_price: dealType === 'SALE' ? apt.price_sell : null,
        rent_amount: dealType === 'RENT' ? apt.price_rent : null,
        security_deposit: rentForm.security_deposit ? Number(rentForm.security_deposit) : 0,
        rent_end_date: dealType === 'RENT' ? rentForm.rent_end_date : null,
      });
      setMsg(`Deal closed successfully! ${dealType === 'RENT' ? 'Rent agreement generated.' : 'Sale recorded.'}`);
      setActionModal(null);
      load();
    } catch (ex) {
      setErr(ex.response?.data?.detail || 'Error closing deal');
    } finally {
      setLoading(false);
    }
  };

  const handleFailDeal = async () => {
    setLoading(true);
    try {
      await api.post(`/agent/fail-deal/${actionModal.apt.appointment_id}`);
      setMsg('Appointment marked as unsuccessful.');
      setActionModal(null);
      load();
    } catch (ex) {
      setErr(ex.response?.data?.detail || 'Error updating appointment');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div>
      {msg && <div className="alert alert-success">{msg}</div>}

      <div style={{ marginBottom: 16, display: 'flex', gap: 4 }}>
        {['upcoming', 'pending', 'done', 'all'].map(f => (
          <button key={f} className={`tab${filter === f ? ' active' : ''}`} onClick={() => setFilter(f)}>
            {f.charAt(0).toUpperCase() + f.slice(1)}
          </button>
        ))}
      </div>

      <DataTable
        title="My Appointments"
        columns={[
          { header: 'Buyer', accessor: 'buyer_name' },
          { header: 'Phone', accessor: 'buyer_phone' },
          { header: 'Location', render: r => `${r.house_no}, ${r.street}, ${r.city}` },
          {
            header: 'Type', accessor: 'listing_type',
            render: r => <span className={`badge ${r.listing_type === 'RENT' ? 'badge-info' : 'badge-accent'}`}>{r.listing_type}</span>
          },
          {
            header: 'Listed Price',
            render: r => r.listing_type === 'RENT'
              ? <><strong>{fmtCurrency(r.price_rent)}/mo</strong></>
              : <><strong>{fmtCurrency(r.price_sell)}</strong></>
          },
          { header: 'Bedrooms', accessor: 'bedrooms' },
          { header: 'Scheduled', accessor: 'schedule_date_time', render: r => fmtDateTime(r.schedule_date_time) },
          {
            header: 'Status', accessor: 'deal_status',
            render: r => (
              <span className={`badge ${r.deal_status ? 'badge-success' : 'badge-warning'}`}>
                {r.deal_status ? 'Closed' : 'Open'}
              </span>
            )
          },
          {
            header: 'Actions', sortable: false,
            render: r => !r.deal_status && (
              <div style={{ display: 'flex', gap: 6 }}>
                <button
                  className="btn btn-success btn-sm"
                  onClick={() => openSuccessModal(r)}
                  title="Deal Successful"
                >
                  <CheckCircle size={12} /> Successful
                </button>
                <button
                  className="btn btn-danger btn-sm"
                  style={{ background: '#ef444422', color: '#ef4444', border: '1px solid #ef444444' }}
                  onClick={() => { setErr(''); setActionModal({ apt: r, mode: 'fail' }); }}
                  title="Deal Unsuccessful"
                >
                  <XCircle size={12} /> Failed
                </button>
              </div>
            )
          },
        ]}
        data={apts}
      />

      {/* Success Modal — close deal */}
      {actionModal?.mode === 'success' && (
        <div className="modal-overlay" onClick={() => setActionModal(null)}>
          <div className="modal" style={{ maxWidth: 480 }} onClick={e => e.stopPropagation()}>
            <div className="modal-title"><CheckCircle size={16} style={{ color: '#4ade80' }} /> Close Deal — Successful</div>

            {/* Property & Price Summary */}
            <div style={{ background: 'var(--bg-secondary)', borderRadius: 8, padding: '12px 14px', marginBottom: 16, fontSize: '0.88rem' }}>
              <div style={{ fontWeight: 600 }}>{actionModal.apt.house_no}, {actionModal.apt.street}, {actionModal.apt.city}</div>
              <div style={{ marginTop: 6, display: 'flex', gap: 16 }}>
                <div>
                  <span style={{ fontSize: '0.72rem', color: 'var(--text-muted)' }}>Buyer</span>
                  <div style={{ fontWeight: 500 }}>{actionModal.apt.buyer_name}</div>
                </div>
                <div>
                  <span style={{ fontSize: '0.72rem', color: 'var(--text-muted)' }}>Deal Type</span>
                  <div style={{ fontWeight: 500 }}>{actionModal.apt.listing_type}</div>
                </div>
                <div>
                  <span style={{ fontSize: '0.72rem', color: 'var(--text-muted)' }}>
                    {actionModal.apt.listing_type === 'RENT' ? 'Monthly Rent' : 'Sale Price'}
                  </span>
                  <div style={{ fontWeight: 700, color: 'var(--accent)', fontSize: '1.05rem' }}>
                    {actionModal.apt.listing_type === 'RENT'
                      ? `${fmtCurrency(actionModal.apt.price_rent)}/mo`
                      : fmtCurrency(actionModal.apt.price_sell)}
                  </div>
                </div>
              </div>
              <div style={{ marginTop: 8, fontSize: '0.75rem', color: '#4ade80' }}>
                ✓ Price is fixed as listed — no manual price entry needed
              </div>
            </div>

            {err && <div className="alert alert-error"><AlertCircle size={14} /> {err}</div>}

            {/* RENT-only: additional fields */}
            {actionModal.apt.listing_type === 'RENT' ? (
              <form onSubmit={handleCloseDeal}>
                <div className="form-row">
                  <div className="form-group">
                    <label className="form-label">Rent Period (months) *</label>
                    <select
                      className="form-select"
                      value={rentForm.rent_period_months}
                      onChange={e => handleRentMonthsChange(e.target.value)}
                    >
                      {[3, 6, 11, 12, 18, 24, 36, 48, 60].map(m => (
                        <option key={m} value={m}>{m} months {m === 11 ? '(11-month agreement)' : m === 12 ? '(1 year)' : m === 24 ? '(2 years)' : ''}</option>
                      ))}
                    </select>
                  </div>
                  <div className="form-group">
                    <label className="form-label">Security Deposit (₹)</label>
                    <input
                      className="form-input"
                      type="number"
                      min="0"
                      placeholder={`e.g. ${actionModal.apt.price_rent * 2}`}
                      value={rentForm.security_deposit}
                      onChange={e => setRentForm(f => ({ ...f, security_deposit: e.target.value }))}
                    />
                  </div>
                </div>
                <div className="form-group">
                  <label className="form-label">Agreement End Date *</label>
                  <input
                    className="form-input"
                    type="date"
                    value={rentForm.rent_end_date}
                    onChange={e => setRentForm(f => ({ ...f, rent_end_date: e.target.value }))}
                    required
                  />
                  <small style={{ color: 'var(--text-muted)', fontSize: '0.75rem' }}>
                    Auto-calculated from period — adjust if needed
                  </small>
                </div>
                <div style={{ background: 'var(--bg-secondary)', borderRadius: 8, padding: '10px 14px', marginBottom: 16, fontSize: '0.82rem' }}>
                  <strong>Rent Agreement Summary</strong>
                  <div style={{ marginTop: 6, display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 8 }}>
                    <div>Monthly Rent: <strong>{fmtCurrency(actionModal.apt.price_rent)}</strong></div>
                    <div>Period: <strong>{rentForm.rent_period_months} months</strong></div>
                    <div>Total Value: <strong>{fmtCurrency(actionModal.apt.price_rent * rentForm.rent_period_months)}</strong></div>
                    <div>Security Deposit: <strong>{rentForm.security_deposit ? fmtCurrency(rentForm.security_deposit) : '₹0'}</strong></div>
                    <div>End Date: <strong>{rentForm.rent_end_date || '—'}</strong></div>
                  </div>
                </div>
                <div className="modal-footer">
                  <button type="button" className="btn btn-secondary" onClick={() => setActionModal(null)}>Cancel</button>
                  <button type="submit" className="btn btn-primary" disabled={loading}>
                    <CheckCircle size={14} /> {loading ? 'Processing…' : 'Generate Rent Agreement'}
                  </button>
                </div>
              </form>
            ) : (
              /* SALE — just confirm */
              <div>
                <p style={{ fontSize: '0.88rem', color: 'var(--text-secondary)', marginBottom: 20 }}>
                  Confirm the sale of this property at the listed price of <strong>{fmtCurrency(actionModal.apt.price_sell)}</strong>?
                  This will close the listing and record the transaction.
                </p>
                <div className="modal-footer">
                  <button className="btn btn-secondary" onClick={() => setActionModal(null)}>Cancel</button>
                  <button
                    className="btn btn-primary"
                    disabled={loading}
                    onClick={handleCloseDeal}
                  >
                    <CheckCircle size={14} /> {loading ? 'Processing…' : 'Confirm Sale'}
                  </button>
                </div>
              </div>
            )}
          </div>
        </div>
      )}

      {/* Fail Deal Confirmation Modal */}
      {actionModal?.mode === 'fail' && (
        <div className="modal-overlay" onClick={() => setActionModal(null)}>
          <div className="modal" style={{ maxWidth: 420 }} onClick={e => e.stopPropagation()}>
            <div className="modal-title" style={{ color: '#ef4444' }}><XCircle size={16} /> Mark Deal as Unsuccessful</div>
            <p style={{ fontSize: '0.88rem', color: 'var(--text-secondary)', marginBottom: 20 }}>
              Are you sure the deal for <strong>{actionModal.apt.house_no}, {actionModal.apt.city}</strong> with buyer <strong>{actionModal.apt.buyer_name}</strong> was unsuccessful?
            </p>
            <p style={{ fontSize: '0.8rem', color: 'var(--text-muted)', marginBottom: 20 }}>
              The appointment will remain in history. The listing will stay active for future bookings.
            </p>
            {err && <div className="alert alert-error"><AlertCircle size={14} /> {err}</div>}
            <div className="modal-footer">
              <button className="btn btn-secondary" onClick={() => setActionModal(null)}>Cancel</button>
              <button
                className="btn btn-danger"
                style={{ background: '#ef4444', color: '#fff' }}
                disabled={loading}
                onClick={handleFailDeal}
              >
                <XCircle size={14} /> {loading ? 'Processing…' : 'Mark as Failed'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// ── Listings — FIXED: use /client/listings/browse not /manager/listings ───────
function ListingsView() {
  const [listings, setListings] = useState([]);
  const [error, setError] = useState('');

  useEffect(() => {
    api.get('/client/listings/browse?status=ACTIVE&page_size=100')
      .then(r => setListings(r.data.listings || []))
      .catch(ex => setError(ex.response?.data?.detail || 'Failed to load listings'));
  }, []);

  if (error) return <div className="alert alert-error"><AlertCircle size={14} /> {error}</div>;

  return (
    <DataTable
      title="All Active Listings"
      columns={[
        {
          header: 'Type', accessor: 'listing_type',
          render: r => <span className={`badge ${r.listing_type === 'RENT' ? 'badge-info' : r.listing_type === 'BOTH' ? 'badge-warning' : 'badge-accent'}`}>{r.listing_type}</span>
        },
        { header: 'Property', accessor: 'property_type' },
        { header: 'City', accessor: 'city' },
        { header: 'Locality', accessor: 'locality_name' },
        { header: 'Bedrooms', accessor: 'bedrooms' },
        { header: 'Rent/mo', accessor: 'price_rent', render: r => r.price_rent ? fmtCurrency(r.price_rent) : '—' },
        { header: 'Sale Price', accessor: 'price_sell', render: r => r.price_sell ? fmtCurrency(r.price_sell) : '—' },
        {
          header: 'Status', accessor: 'status',
          render: r => {
            const c = { ACTIVE: 'badge-success', SOLD: 'badge-muted', RENTED: 'badge-info', WITHDRAWN: 'badge-danger' };
            return <span className={`badge ${c[r.status] || 'badge-muted'}`}>{r.status}</span>;
          }
        },
        { header: 'Owner', accessor: 'owner_name' },
      ]}
      data={listings}
    />
  );
}

// ── Performance ───────────────────────────────────────────────────────────────
function PerformanceView({ agentId }) {
  const [perf, setPerf] = useState(null);
  const [error, setError] = useState('');

  useEffect(() => {
    if (!agentId) return;
    api.get(`/agent/performance/${agentId}`)
      .then(r => setPerf(r.data))
      .catch(ex => setError(ex.response?.data?.detail || 'Failed to load performance data'));
  }, [agentId]);

  if (error) return <div className="alert alert-error"><AlertCircle size={14} /> {error}</div>;
  if (!perf) return <div className="loading"><div className="spinner" />Loading…</div>;

  return (
    <div>
      <div className="stats-grid">
        <StatCard icon={CalendarCheck} label="Total Appointments" value={perf.summary.total_appointments || 0} />
        <StatCard icon={CheckCircle} label="Deals Closed" value={perf.summary.successful_deals || 0} color="#4ade80" />
        <StatCard icon={Target} label="Conversion Rate" value={`${perf.summary.conversion_rate || 0}%`} color="#60a5fa" />
        <StatCard icon={DollarSign} label="Total Revenue" value={fmtCurrency(perf.summary.total_revenue)} color="#fbbf24" />
      </div>
      <div className="card">
        <div className="card-title">Monthly Performance</div>
        <div style={{ height: 260 }}>
          <ResponsiveContainer>
            <LineChart data={perf.monthly}>
              <XAxis dataKey="month" tick={{ fill: 'var(--text-muted)', fontSize: 11 }} tickLine={false} />
              <YAxis tick={{ fill: 'var(--text-muted)', fontSize: 10 }} tickFormatter={v => fmtCurrency(v)} tickLine={false} axisLine={false} />
              <Tooltip formatter={v => [fmtCurrency(v), 'Revenue']} contentStyle={{ background: 'var(--bg-card)', border: '1px solid var(--border)', borderRadius: 8 }} />
              <Line type="monotone" dataKey="revenue" stroke="var(--accent)" strokeWidth={2} dot={{ fill: 'var(--accent)' }} />
              <Line type="monotone" dataKey="deals" stroke="#60a5fa" strokeWidth={2} dot={{ fill: '#60a5fa' }} />
            </LineChart>
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
}

// ── Root ──────────────────────────────────────────────────────────────────────
const views = {
  dashboard:    { title: 'Dashboard',    sub: 'Your performance overview',    Component: DashboardView },
  performance:  { title: 'Performance',  sub: 'Detailed stats',               Component: PerformanceView },
  appointments: { title: 'Appointments', sub: 'Your assigned appointments',   Component: AppointmentsView },
  listings:     { title: 'Listings',     sub: 'All active listings',          Component: ListingsView },
};

export default function AgentDashboard() {
  const { user } = useAuth();
  const [active, setActive] = useState('dashboard');
  const view = views[active] || views.dashboard;
  const { Component } = view;

  return (
    <div className="app-shell">
      <Sidebar active={active} onChange={setActive} />
      <div className="main-content">
        <div className="topbar">
          <span className="topbar-title">Agent Panel — {user?.name}</span>
        </div>
        <div className="page">
          <div className="page-header">
            <h1>{view.title}</h1>
            <p>{view.sub}</p>
          </div>
          <Component agentId={user?.id} />
        </div>
      </div>
    </div>
  );
}
